SELECT city_name 
FROM cities 
WHERE state_id IN (
    SELECT state_id 
    FROM states
);

SELECT *
FROM cities
ORDER BY city_name ASC;

SELECT cities.city_name, census_data.population, census_data.density
FROM cities
INNER JOIN census_data ON cities.city_id = census_data.city_id;

SELECT COUNT(DISTINCT city_id) 
FROM access_logs 
WHERE user_id = 1;
